import re
import operator
from functools import partial

# Supported comparison operators
_COMPARATORS = {
    '=': operator.eq,
    '!=': operator.ne,
    '<': operator.lt,
    '<=': operator.le,
    '>': operator.gt,
    '>=': operator.ge,
}

_LOGICAL_AND = 'AND'
