    # Token specs (order matters)
    token_specification = [
        ('SKIP',       r'[ \t\r\n]+'),
        ('LPAREN',     r'\('),
        ('RPAREN',     r'\)'),
        ('OP',         r'<=|>=|!=|=|<|>'),
        ('AND',        r'(?i:\bAND\b)'),
        ('OR',         r'(?i:\bOR\b)'),
        ('SSTRING',    r"'(?:\\.|[^'])*'"),
        ('DSTRING',    r'"(?:\\.|[^"])*"'),
        ('NUMBER',     r'[-+]?(?:\d+\.\d*|\.\d+|\d+)(?:[eE][-+]?\d+)?'),
        ('IDENT',      r'[A-Za-z_][A-Za-z0-9_]*'),
        ('MISMATCH',   r'.'),
    ]
